import{_ as e,o as s,c as a,a2 as t}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md"}'),o={name:"guide/troubleshooting.md"};function n(l,i,r,h,p,d){return s(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><h2 id="port-already-in-use" tabindex="-1">Port already in use <a class="header-anchor" href="#port-already-in-use" aria-label="Permalink to &quot;Port already in use&quot;">​</a></h2><p>If <code>bash scripts/install.sh</code> fails with a bind error, check which process owns the port:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tulpn</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Stop the conflicting process or change your host mapping, then rerun:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/install.sh</span></span></code></pre></div><h2 id="sip-not-registering" tabindex="-1">SIP not registering <a class="header-anchor" href="#sip-not-registering" aria-label="Permalink to &quot;SIP not registering&quot;">​</a></h2><p>Check these first:</p><ul><li><code>SIP_PORT</code> must be <code>5080</code>.</li><li>Host firewall must allow SIP traffic on <code>5080</code> (UDP/TCP).</li><li>Extension username/password in your softphone must exactly match the credentials provisioned in Callytics.</li></ul><p>If registration still fails, inspect Asterisk and backend logs to confirm the auth challenge and endpoint state.</p><h2 id="audio-not-playing" tabindex="-1">Audio not playing <a class="header-anchor" href="#audio-not-playing" aria-label="Permalink to &quot;Audio not playing&quot;">​</a></h2><p>Validate in order:</p><ul><li>In the Audio page, confirm the file upload completed.</li><li>Confirm conversion completed successfully.</li><li>Confirm the Asterisk container is healthy.</li></ul><p>If the file appears in UI but playback still fails, check container logs and media mount visibility.</p><h2 id="one-way-audio" tabindex="-1">One-way audio <a class="header-anchor" href="#one-way-audio" aria-label="Permalink to &quot;One-way audio&quot;">​</a></h2><p>Most one-way audio incidents are NAT/router related:</p><ul><li>Disable SIP ALG on your router.</li><li>Open RTP port range <code>10000-20000/udp</code>.</li><li>Check NAT detection result in the preflight wizard and apply the suggested network configuration.</li></ul><h2 id="docker-socket-permission-denied" tabindex="-1">Docker socket permission denied <a class="header-anchor" href="#docker-socket-permission-denied" aria-label="Permalink to &quot;Docker socket permission denied&quot;">​</a></h2><p>If backend operations fail with Docker socket permission errors, add your user to the Docker group:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $USER</span></span></code></pre></div><p>Then log out and back in (or restart your session) so group membership is applied.</p>',21)])])}const k=e(o,[["render",n]]);export{u as __pageData,k as default};
